@Contract("null -> null")
	public @Nullable String escape(@Nullable String value) {

		return value == null //
				? null //
				: Stream.concat(Stream.of(String.valueOf(escapeCharacter)), TO_REPLACE.stream()) //
					.reduce(value, (it, character) -> it.replace(character, this.escapeCharacter + character));
	}

interface ComposableFilter<T, S> {

	S filter(T first, S second);

	default ComposableFilter<T, S> andThen(ComposableFilter<T, S> filter) {
		return (first, second) -> filter.filter(first, filter(first, second));
	}
}

